func TestPreClaimIntakeWarnFingerprintEscalatesToOperatorAttention(t *testing.T) {
	// Test that N consecutive identical pre-claim warn fingerprints across distinct beads
	// trigger an operator-attention event and stop the loop.
	inner, _, _ := newExecuteLoopTestStore(t)
